{
  "terms": [
    {
      "term": "Mass",
      "simpleDefinition": "The amount of matter in an object, measured in kilograms (kg). It stays the same regardless of location.",
      "anchor": "A 20kg roll of twin and earth cable has the same mass whether it is on the ground or at the top of a ladder.",
      "misconception": "Thinking mass changes if gravity changes; mass is constant."
    },
    {
      "term": "Weight",
      "simpleDefinition": "The force exerted on an object by gravity, measured in Newtons (N).",
      "anchor": "Weight is calculated by multiplying mass by the gravity constant (9.81).",
      "misconception": "Using kilograms to describe weight in technical calculations instead of Newtons."
    },
    {
      "term": "Gravity (g)",
      "simpleDefinition": "The constant acceleration that pulls objects toward Earth, valued at 9.81 m/s².",
      "anchor": "Every 1kg of mass exerts 9.81 Newtons of downward force.",
      "misconception": "Rounding gravity to 10 in exam calculations; always use 9.81 for C&G 2365."
    },
    {
      "term": "Fulcrum",
      "simpleDefinition": "The fixed pivot point that a lever rotates around.",
      "anchor": "The center pin or hinge of a pair of side-cutters.",
      "misconception": "Assuming the pivot must always be in the exact center of the tool."
    },
    {
      "term": "Class I Lever",
      "simpleDefinition": "A lever where the fulcrum is in the middle, between the effort and the load.",
      "anchor": "A pair of pliers or a crowbar.",
      "misconception": "Thinking all levers are Class I."
    },
    {
      "term": "Class II Lever",
      "simpleDefinition": "A lever where the load is in the middle, between the fulcrum and the effort.",
      "anchor": "A wheelbarrow used to move heavy bags of plaster.",
      "misconception": "Confusing the position of the load and the fulcrum."
    },
    {
      "term": "Class III Lever",
      "simpleDefinition": "A lever where the effort is in the middle, between the fulcrum and the load.",
      "anchor": "A pair of tweezers or a set of sugar tongs.",
      "misconception": "Believing Class III levers are designed to make heavy loads easier to lift; they are usually for precision or speed."
    },
    {
      "term": "Gear",
      "simpleDefinition": "A toothed wheel that meshes with others to change the speed or torque of a mechanical system.",
      "anchor": "The internal drive system of a cordless power drill.",
      "misconception": "Thinking gears only change speed; they also change the turning force (torque)."
    },
    {
      "term": "Pulley",
      "simpleDefinition": "A wheel with a grooved rim for a rope or cable, used to lift loads or change the direction of a force.",
      "anchor": "A block and tackle used to hoist a heavy distribution board into place.",
      "misconception": "Thinking a single fixed pulley reduces the effort needed; it only changes the direction of the pull."
    }
  ],
  "anchorPhrases": [
    "Mass is the quantity of matter; Weight is the force of gravity.",
    "Weight (N) = Mass (kg) × 9.81.",
    "Class I: Fulcrum in the middle.",
    "Class II: Load in the middle.",
    "Class III: Effort in the middle."
  ],
  "misconceptionTargets": [
    "Mass and weight are the same thing.",
    "Weight is measured in kilograms.",
    "All levers have the pivot point in the middle.",
    "Gears only change speed, not force."
  ]
}

{
  "teachChecks": [
    {
      "title": "Mass vs Weight",
      "objective": "Differentiate between mass as a quantity of matter and weight as a force.",
      "retrievalTextLines": [
        "In the electrical trade, precision matters when calculating the load on tray work or fixings. We start by distinguishing between mass and weight. Mass is the actual quantity of matter in an object, measured in kilograms (kg). Whether a 20kg roll of cable is on the ground or at the top of a ladder, its mass remains exactly 20kg. It is constant and does not change based on location.",
        "Weight, however, is a force. It is the pull of gravity on that mass, measured in Newtons (N). To find the weight of an object, you multiply the mass by the constant for gravity (g), which is 9.81 m/s². For example, that 20kg roll of cable exerts a downward force of 196.2 Newtons (20kg × 9.81). Electricians often mistake these terms in casual conversation, but for technical calculations, you must remember: mass is the 'stuff' (kg), and weight is the 'force' (N). Always use 9.81 for gravity in your C&G 2365 calculations to ensure accuracy when specifying support systems for heavy equipment."
      ],
      "hint": "Remember that mass is measured in kg and stays the same, while weight is a force in Newtons calculated using gravity (9.81)."
    },
    {
      "title": "Levers, Gears, and Pulleys",
      "objective": "Identify the three classes of levers and the basic function of gears and pulleys.",
      "retrievalTextLines": [
        "Mechanical systems like levers, gears, and pulleys allow us to move heavy loads with less effort. A lever consists of a rigid bar pivoting on a fixed point called a fulcrum. There are three classes based on the positions of the Fulcrum, Load, and Effort. In a Class I lever, the fulcrum is in the middle, between the effort and the load, like a pair of pliers or side-cutters. In a Class II lever, the load is in the middle, such as a wheelbarrow moving heavy bags of plaster. In a Class III lever, the effort is in the middle, like a pair of tweezers used for precision work.",
        "Gears and pulleys provide mechanical advantage. Gears are toothed wheels that mesh together; they can change the speed of a motor or increase the turning force (torque) in a power drill. Pulleys use a grooved wheel and a rope to lift loads. While a single pulley might only change the direction of the pull, a system of pulleys (block and tackle) makes lifting heavy distribution boards much easier by reducing the required effort."
      ],
      "hint": "Focus on what is in the middle: Class I is the Fulcrum, Class II is the Load, and Class III is the Effort."
    }
  ]
}

