      "deeperQuestionText": "Why would an electrician use a block and tackle pulley system instead of a single fixed pulley when lifting a heavy distribution board?",
      "deeperAnswerGuidance": [
        "A single pulley only changes the direction of the force",
        "A block and tackle provides mechanical advantage",
        "It reduces the effort required to lift the heavy load",
        "Multiple pulleys distribute the weight across more ropes"
      ],
      "hint": "Think about which component (Fulcrum, Load, or Effort) is in the middle for each lever class."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice: Calculating Force on a Fixing",
    "objective": "Calculate the weight of an electrical component in Newtons to determine the downward force on its fixings.",
    "retrievalTextLines": [
      "Step 1: Identify the mass of the object in kilograms (kg).",
      "Step 2: Use the standard gravity constant for the UK: 9.81 m/s².",
      "Step 3: Apply the formula: Weight (N) = Mass (kg) × 9.81."
    ],
    "questionText": "A metal distribution board has a mass of 12 kg. Calculate the weight (downward force) this board will exert on its wall fixings in Newtons.",
    "answerGuidance": [
      "117.72 N",
      "117.72 Newtons"
    ],
    "hint": "Multiply the mass (12) by the gravity constant (9.81)."
  },
  "practice": {
    "title": "Independent Practice: Mechanical Systems and Force",
    "objective": "Categorize a lever type used in electrical work and calculate the weight of a load.",
    "retrievalTextLines": [
      "Class I Lever: Fulcrum is in the middle (e.g., pliers).",
      "Class II Lever: Load is in the middle (e.g., wheelbarrow).",
      "Class III Lever: Effort is in the middle (e.g., tweezers).",
      "Weight (N) = Mass (kg) × 9.81."
    ],
    "questionText": "You are using a crowbar to pry up a heavy cable duct. The pivot point (fulcrum) is located between your hands (effort) and the duct (load). 1) Identify the lever class. 2) If the section of duct has a mass of 15 kg, calculate its weight in Newtons.",
    "answerGuidance": [
      "Class I",
      "147.15 N"
    ],
    "hint": "For the lever, identify which component is in the middle. For the weight, use the mass of 15 kg and the standard gravity constant."
  }
}

